import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './components/Login';
import ListaProductos from './components/ListaProductos'; // Importar el nuevo componente

function App() {
  return (
    <Router>
      <div style={{ textAlign: 'center' }}>
        <h1 style={{ background: '#28a745', color: 'white', padding: '20px' }}>EcoDespensa 🍎</h1>
        <Routes>
          <Route path="/" element={<Login />} />
          <Route path="/login" element={<Login />} />
          <Route path="/productos" element={<ListaProductos />} /> {/* Nueva ruta */}
        </Routes>
      </div>
    </Router>
  );
}

export default App;
